import{_ as s,o as i,c as a,a as n}from"./chunks/framework.8tiMeCK-.js";const t="/PenguinLab/assets/ch05_fig048.D32zm7Ed.webp",g=JSON.parse('{"title":"5.4  Configuring Generic KASAN Mode","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/linux_kernel_debugging/ch05_4.md","filePath":"en/notes/linux_kernel_debugging/ch05_4.md","lastUpdated":null}'),o={name:"en/notes/linux_kernel_debugging/ch05_4.md"};function r(l,e,h,c,p,d){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_5-4-configuring-generic-kasan-mode" tabindex="-1">5.4 Configuring Generic KASAN Mode <a class="header-anchor" href="#_5-4-configuring-generic-kasan-mode" aria-label="Permalink to &quot;5.4  Configuring Generic KASAN Mode&quot;">​</a></h1><p>Since we decided to start with Generic KASAN, we first need to &quot;arm&quot; the kernel.</p><p>The configuration process itself isn&#39;t complicated, but it&#39;s like swapping an engine in a race car—even though you&#39;re just tightening a few screws, you know that once they&#39;re in place, the machine&#39;s entire operational logic changes.</p><h3 id="enabling-generic-kasan" tabindex="-1">Enabling Generic KASAN <a class="header-anchor" href="#enabling-generic-kasan" aria-label="Permalink to &quot;Enabling Generic KASAN&quot;">​</a></h3><p>The first step is routine: open the kernel configuration menu.</p><p>If you are configuring for ARM64 (our default architecture for this demo), the command is:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> menuconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>In the menu, navigate the following path to find the KASAN toggle: <code>Kernel hacking</code> → <code>Memory Debugging</code> → <code>KASAN: runtime memory debugger</code></p><p>After entering this submenu, you will see the mode selection options. Here we keep the default, which is <strong>Generic KASAN</strong> mode.</p><p><img src="'+t+`" alt="Kernel Configuration Menu"><em>Figure 5.1 – Kernel configuration screenshot for enabling KASAN</em></p><p>When you highlight the <code>Config KASAN as generic mode</code> option and press the <code>&lt; Help &gt;</code> key, a prompt will pop up that is worth spending 10 seconds to read. This isn&#39;t just a description—it&#39;s telling you the &quot;price&quot;:</p><blockquote><p>This mode consumes about 1/8th of available memory at kernel start and introduces an overhead of ~x1.5 for the rest of the allocations. The performance slowdown is ~x3.</p></blockquote><p>In plain English:</p><ol><li><strong>Memory</strong>: At kernel boot, it will immediately consume <strong>1/8</strong> of your physical memory. If your board only has 512MB of RAM, this cut will hurt.</li><li><strong>Allocation Overhead</strong>: The overhead for all memory allocations will increase by about <strong>1.5x</strong>.</li><li><strong>Overall Performance</strong>: System execution speed will slow down by roughly <strong>3x</strong>.</li></ol><p>This is the down payment you make to catch those ghost-like bugs.</p><p>After saving the configuration and exiting, we can see exactly what changed in the <code>.config</code> file.</p><p>For the ARM64 architecture, a specific set of macros will appear in <code>.config</code> (note the presence of <code>SHADOW_OFFSET</code> and <code>SW_TAGS</code>):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> KASAN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .config</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_KASAN_SHADOW_OFFSET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0xdfffffd000000000</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_HAVE_ARCH_KASAN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_HAVE_ARCH_KASAN_SW_TAGS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_CC_HAS_KASAN_GENERIC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_KASAN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_KASAN_GENERIC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>There is a key piece of information here: <code>CONFIG_KASAN_SHADOW_OFFSET</code>. This is the base address (Kernel Virtual Address) of the &quot;shadow memory&quot; we mentioned earlier. The kernel relies on this value to map your actual memory addresses to this dedicated shadow region, thereby recording the state of each memory segment (whether it is readable, freed, etc.).</p><hr><h3 id="kasan-s-impact-on-the-compilation-process" tabindex="-1">KASAN&#39;s Impact on the Compilation Process <a class="header-anchor" href="#kasan-s-impact-on-the-compilation-process" aria-label="Permalink to &quot;KASAN&#39;s Impact on the Compilation Process&quot;">​</a></h3><p>Simply enabling <code>CONFIG_KASAN=y</code> isn&#39;t enough; the compiler&#39;s behavior also undergoes a fundamental change.</p><p>If you recompile the kernel with the <code>V=1</code> parameter (<code>make V=1</code>), you will see a flurry of GCC parameters flying across the screen. If we capture a snippet, you will see a compilation command like this:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> V=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Wp,-MMD,[...]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsanitize=kernel-address</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-fasan-shadow-offset=0xdffffc0000000000 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--param</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">asan-globals=1 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--param</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> asan-instrumentation-with-call-threshold=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--param </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">asan-stack=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --param</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> asan-instrument-allocas=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Pay attention to these key parameters:</p><ul><li><strong><code>-fsanitize=kernel-address</code></strong>: This is the master switch for compiler instrumentation. It tells GCC: &quot;In this compilation unit, I want to check all memory accesses.&quot;</li><li><strong><code>-fasan-shadow-offset=...</code></strong>: Tells the compiler the starting offset of the shadow memory, so the generated check code can calculate the correct shadow address.</li></ul><p><strong>The essence of how KASAN works is: every time you read or write memory, it intervenes.</strong></p><p>This uses a technique called <strong>Compile-Time Instrumentation</strong>. Simply put, during the compilation phase, the compiler secretly inserts some &quot;check code&quot; into your code.</p><p>Whenever you have a line of code that attempts to read 1, 2, 4, 8, or 16 bytes of memory, the compiler actually generates logic similar to this:</p><ol><li>Call the <code>__asan_load*()</code> function (Outline mode)</li><li>Or directly insert a block of check logic (Inline mode)</li></ol><p>By checking the value in the corresponding &quot;shadow memory,&quot; the runtime can determine: is this access legitimate, or are we &quot;reading/writing out of bounds&quot;?</p><h4 id="outline-vs-inline-two-schools-of-instrumentation" tabindex="-1">Outline vs. Inline: Two Schools of Instrumentation <a class="header-anchor" href="#outline-vs-inline-two-schools-of-instrumentation" aria-label="Permalink to &quot;Outline vs. Inline: Two Schools of Instrumentation&quot;">​</a></h4><p>Since we mentioned instrumentation, there is an important configuration option worth your attention that determines the &quot;depth&quot; of the compiler&#39;s intervention.</p><p>In the configuration menu, you will see the <strong><code>Instrumentation type</code></strong> option. It corresponds to two kernel configuration macros:</p><ul><li><strong><code>CONFIG_KASAN_OUTLINE</code></strong> (default): <strong>Outline instrumentation</strong>. <ul><li>The compiler inserts actual <strong>function calls</strong> (such as <code>__asan_load1</code>).</li><li><strong>Pros</strong>: The resulting kernel image size is <strong>smaller</strong> (there is only one copy of the check code).</li><li><strong>Cons</strong>: Every access must go through the function call process, resulting in relatively higher performance overhead.</li></ul></li><li><strong><code>CONFIG_KASAN_INLINE</code></strong>: <strong>Inline instrumentation</strong>. <ul><li>The compiler directly hard-copies the check <strong>logic code</strong> to every single memory access point.</li><li><strong>Pros</strong>: <strong>Faster speed</strong> (saves the overhead of function calls), typically 1.1x to 2x faster than Outline.</li><li><strong>Cons</strong>: The kernel image size will <strong>balloon significantly</strong> (because the check code is copied countless times).</li></ul></li></ul><p>This is a classic engineering trade-off. For kernel debugging, the default Outline mode is usually sufficient; but if you find KASAN too slow and it affects the reproduction of certain timing-related bugs, switching to Inline mode might bring a pleasant surprise.</p><hr><h3 id="auxiliary-configuration-making-reports-more-readable" tabindex="-1">Auxiliary Configuration: Making Reports More Readable <a class="header-anchor" href="#auxiliary-configuration-making-reports-more-readable" aria-label="Permalink to &quot;Auxiliary Configuration: Making Reports More Readable&quot;">​</a></h3><p>When KASAN catches a bug, it throws a report. To make this report more valuable—not just telling you &quot;it crashed,&quot; but telling you &quot;who did it&quot;—we recommend enabling the following two options while you&#39;re at it.</p><h4 id="_1-enable-stack-traces" tabindex="-1">1. Enable Stack Traces <a class="header-anchor" href="#_1-enable-stack-traces" aria-label="Permalink to &quot;1. Enable Stack Traces&quot;">​</a></h4><p>Make sure to enable <code>CONFIG_STACKTRACE</code>.</p><p>This makes KASAN print not only the current access stack when reporting an error, but also &quot;when this memory was allocated&quot; and &quot;when it was freed.&quot; This is crucial for locating <code>Use-After-Free</code> (use-after-free) issues.</p><h4 id="_2-track-page-owners" tabindex="-1">2. Track Page Owners <a class="header-anchor" href="#_2-track-page-owners" aria-label="Permalink to &quot;2. Track Page Owners&quot;">​</a></h4><p>Under the <code>Kernel hacking</code> → <code>Memory Debugging</code> menu, find and enable <code>Track page owner</code> (corresponding to <code>CONFIG_PAGE_OWNER</code>).</p><p>This isn&#39;t just for KASAN; it&#39;s a general kernel memory debugging feature that records the allocation and free history stack of every physical page.</p><p>⚠️ <strong>Warning</strong><code>page_owner</code> is off by default. Even if you compile it in, you need to add <code>page_owner=on</code> to the kernel boot parameters for it to actually take effect.</p><hr><h3 id="a-special-option-on-x86-64-vmalloc-space" tabindex="-1">A Special Option on x86_64: vmalloc Space <a class="header-anchor" href="#a-special-option-on-x86-64-vmalloc-space" aria-label="Permalink to &quot;A Special Option on x86_64: vmalloc Space&quot;">​</a></h3><p>If you are configuring on the x86_64 architecture, you will find an extra option that is usually not present on ARM64:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] Back mappings in vmalloc space with real shadow memory</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The purpose of this option is to <strong>map the vmalloc space</strong> with real shadow memory.</p><p>With this enabled, KASAN can detect vmalloc-related memory corruption issues (such as out-of-bounds writes into vmalloc-allocated areas). The cost, naturally, is a further increase in runtime memory usage. If you are debugging driver modules (which are frequently loaded into vmalloc space), this option is very useful.</p><hr><h3 id="ready-for-ignition" tabindex="-1">Ready for Ignition <a class="header-anchor" href="#ready-for-ignition" aria-label="Permalink to &quot;Ready for Ignition&quot;">​</a></h3><p>That&#39;s enough theory for now.</p><p>The current task is: follow the steps above to configure and rebuild your &quot;debug kernel.&quot;</p><p>Compile it, flash it, and reboot. When the system successfully boots and you see that familiar login prompt—even though it might be a few beats slower than usual—you will have X-ray vision, ready to catch those memory bugs hiding in the dark corners.</p>`,57)])])}const k=s(o,[["render",r]]);export{g as __pageData,k as default};
